func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	var rand_range [MAXASSIGNS]int
	var rand_limit int = 0 //记录有多少个有车的assign

	logger := zap.L().Named("Insert")

	// 生成随机序列 TODO: 有些车在时间触发过程中可能变空了
	for ii := range rand_range {
		rand_range[ii] = ii
		// 交换不空的解
		if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen > 0 {
			rand_range[ii], rand_range[rand_limit] = rand_range[rand_limit], ii
			// 记录有多少个不空的解
			rand_limit += 1
		}
	}
	//由于不空的解都在前面，所以只需要打乱前面这部分
	rand.Shuffle(rand_limit, func(i, j int) {
		rand_range[i], rand_range[j] = rand_range[j], rand_range[i]
	})

	// 开始插入
	for jj := range oris {
		for _, ii := range rand_range {
			//尝试插入解
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {

				dispatch.Assigns[ii].Cost = -1

			} else {
				dispatch.Assigns[ii].GenRoute()

			}
			//插入失败
			if dispatch.Assigns[ii].Cost < 0 {
				//fmt.Println("inserted but not avaliable")
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				//如果插入成功，并且插入了一辆空车，那么扩展一辆车
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen += 1
				}
				break
			}
			// 应当一定有一辆车能插入成功,否则第assignslen也插入失败的话，说明该订单插不进去
			if ii >= dispatch.AssignsLen {
				logger.Warn(
					"Cannot Insert",
					zap.Int("ship", total_ship+jj),
					zap.Int("non_empty", rand_limit),
					zap.Int("assigns_len", dispatch.AssignsLen),
				)
				fmt.Println(oris[jj], dess[jj])
				dispatch.Assigns[dispatch.AssignsLen].PrettyPrint()
				//dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship + jj, oris[jj], dess[jj])
				//checkDispatch(&dispatch)
				break
			}
		}
	}
	dispatch.RenewnTotalCost()
	//XXX: 调查发现,insertion不会改变累计里程，是别的东西删除了累计里程
	return dispatch
}

population.algorithm:
Greedy insertion with regret-based fallback: try inserting each ship into existing non-empty routes first by best feasible cost improvement; if none work, try empty routes in order; if still none, create a new route.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	nonEmptyRoutes := make([]int, 0, MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].StationsLen > 0 {
			nonEmptyRoutes = append(nonEmptyRoutes, i)
		}
	}
	rand.Shuffle(len(nonEmptyRoutes), func(i, j int) {
		nonEmptyRoutes[i], nonEmptyRoutes[j] = nonEmptyRoutes[j], nonEmptyRoutes[i]
	})
	for _, idx := range orderIndices {
		bestRoute := -1
		bestDelta := math.MaxFloat64
		ori := oris[idx]
		des := dess[idx]
		shipID := total_ship + idx
		attemptedNonEmpty := false
		if len(nonEmptyRoutes) > 0 {
			attemptedNonEmpty = true
			for _, rIdx := range nonEmptyRoutes {
				assignCopy := dispatch.Assigns[rIdx]
				ok := assignCopy.AddShip(shipID, ori, des)
				if ok {
					assignCopy.GenRoute()
					if assignCopy.Cost >= 0 {
						delta := assignCopy.Cost - dispatch.Assigns[rIdx].Cost
						if delta < bestDelta {
							bestDelta = delta
							bestRoute = rIdx
						}
					}
				}
			}
		}
		if bestRoute == -1 {
			for i := 0; i < dispatch.AssignsLen; i++ {
				found := false
				for _, ne := range nonEmptyRoutes {
					if i == ne {
						found = true
						break
					}
				}
				if found {
					continue
				}
				ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[i].GenRoute()
					if dispatch.Assigns[i].Cost >= 0 {
						bestRoute = i
						break
					} else {
						dispatch.Assigns[i].RemoveShip(shipID)
						dispatch.Assigns[i].GenRoute()
					}
				}
			}
		}
		if bestRoute != -1 && attemptedNonEmpty {
			dispatch.Assigns[bestRoute].AddShip(shipID, ori, des)
			dispatch.Assigns[bestRoute].GenRoute()
			if dispatch.Assigns[bestRoute].Cost < 0 {
				dispatch.Assigns[bestRoute].RemoveShip(shipID)
				dispatch.Assigns[bestRoute].GenRoute()
				bestRoute = -1
			}
		}
		if bestRoute == -1 {
			newIdx := dispatch.AssignsLen
			if newIdx >= MAXASSIGNS {
				continue
			}
			ok := dispatch.Assigns[newIdx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[newIdx].GenRoute()
				if dispatch.Assigns[newIdx].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[newIdx].RemoveShip(shipID)
					dispatch.Assigns[newIdx].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

