population.algorithm:
Greedy insertion with fallback to empty vehicle creation using time-window proximity scoring.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    n := len(oris)
    if n == 0 {
        dispatch.RenewnTotalCost()
        return dispatch
    }

    usedAssignIdx := make([]int, 0, dispatch.AssignsLen)
    for i := 0; i < dispatch.AssignsLen; i++ {
        usedAssignIdx = append(usedAssignIdx, i)
    }
    nextNewAssign := dispatch.AssignsLen

    for orderIdx := 0; orderIdx < n; orderIdx++ {
        shipID := total_ship + orderIdx
        ori := oris[orderIdx]
        des := dess[orderIdx]

        bestCostIncrease := math.Inf(1)
        bestAssignIdx := -1

        for _, idx := range usedAssignIdx {
            assignCopy := dispatch.Assigns[idx]
            ok := assignCopy.AddShip(shipID, ori, des)
            if ok {
                assignCopy.GenRoute()
                if assignCopy.Cost >= 0 {
                    baseAssign := dispatch.Assigns[idx]
                    baseCost := baseAssign.Cost
                    if baseCost < 0 {
                        baseCost = 0
                    }
                    inc := assignCopy.Cost - baseCost
                    if inc < bestCostIncrease {
                        bestCostIncrease = inc
                        bestAssignIdx = idx
                    }
                }
            }
            dispatch.Assigns[idx].RemoveShip(shipID)
            dispatch.Assigns[idx].GenRoute()
        }

        if bestAssignIdx != -1 {
            dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
            dispatch.Assigns[bestAssignIdx].GenRoute()
            continue
        }

        fallbackAssigned := false
        for fi := 0; fi < MAXASSIGNS; fi++ {
            if fi < dispatch.AssignsLen {
                ok := dispatch.Assigns[fi].AddShip(shipID, ori, des)
                if ok {
                    dispatch.Assigns[fi].GenRoute()
                    if dispatch.Assigns[fi].Cost >= 0 {
                        fallbackAssigned = true
                        break
                    }
                    dispatch.Assigns[fi].RemoveShip(shipID)
                    dispatch.Assigns[fi].GenRoute()
                }
            } else {
                if nextNewAssign >= MAXASSIGNS {
                    break
                }
                ok := dispatch.Assigns[nextNewAssign].AddShip(shipID, ori, des)
                if ok {
                    dispatch.Assigns[nextNewAssign].GenRoute()
                    if dispatch.Assigns[nextNewAssign].Cost >= 0 {
                        if nextNewAssign >= dispatch.AssignsLen {
                            dispatch.AssignsLen = nextNewAssign + 1
                            usedAssignIdx = append(usedAssignIdx, nextNewAssign)
                        }
                        fallbackAssigned = true
                        break
                    }
                    dispatch.Assigns[nextNewAssign].RemoveShip(shipID)
                    dispatch.Assigns[nextNewAssign].GenRoute()
                }
            }
        }

        if !fallbackAssigned {
            if nextNewAssign < MAXASSIGNS {
                dispatch.Assigns[nextNewAssign].AddShip(shipID, ori, des)
                dispatch.Assigns[nextNewAssign].GenRoute()
                if nextNewAssign >= dispatch.AssignsLen {
                    dispatch.AssignsLen = nextNewAssign + 1
                    usedAssignIdx = append(usedAssignIdx, nextNewAssign)
                }
                nextNewAssign++
            }
        }
    }

    dispatch.RenewnTotalCost()
    return dispatch

