Greedy best-insertion with time-window slack scoring, fallback to earliest-available assign if none feasible.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	nOrders := len(oris)
	if nOrders == 0 || len(dess) != nOrders {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	feasibleExists := false
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].Cost >= 0 {
			feasibleExists = true
			break
		}
	}
	if !feasibleExists && dispatch.AssignsLen > 0 {
		dispatch.Assigns[0].GenRoute()
	}

	type cand struct {
		assignIdx int
		costDelta float64
		score     float64
		insertOk  bool
	}

	for oi := 0; oi < nOrders; oi++ {
		ori := oris[oi]
		des := dess[oi]
		shipID := total_ship + oi

		best := cand{assignIdx: -1, costDelta: 1e100, score: 1e100, insertOk: false}

		limitCheck := dispatch.AssignsLen
		if limitCheck == 0 {
			limitCheck = 1
		}
		if limitCheck > MAXASSIGNS {
			limitCheck = MAXASSIGNS
		}

		checkIndices := make([]int, limitCheck)
		for i := 0; i < limitCheck; i++ {
			checkIndices[i] = i
		}

		origCosts := make([]float64, limitCheck)
		for _, idx := range checkIndices {
			if idx < dispatch.AssignsLen {
				origCosts[idx] = dispatch.Assigns[idx].Cost
			} else {
				origCosts[idx] = 0.0
			}
		}

		for _, idx := range checkIndices {
			isNew := idx >= dispatch.AssignsLen
			var ok bool
			if isNew {
				ok = dispatch.Assigns[idx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[idx].GenRoute()
					ok = dispatch.Assigns[idx].Cost >= 0
				}
			} else {
				oldCost := origCosts[idx]
				ok = dispatch.Assigns[idx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[idx].GenRoute()
					newCost := dispatch.Assigns[idx].Cost
					if newCost < 0 {
						ok = false
					} else {
						delta := newCost - oldCost
						if delta < 0 {
							delta = 0
						}
						timeSlack := 0.0
						asg := &dispatch.Assigns[idx]
						if len(asg.Stations) > 0 {
							last := asg.Stations[len(asg.Stations)-1]
							timeSlack = float64(last.TimeEnd - last.TimeStart)
							if timeSlack < 0 {
								timeSlack = 0
							}
						}
						scoreVal := delta / (timeSlack + 1.0)

						if (!best.insertOk) || (scoreVal < best.score) || (scoreVal == best.score && delta < best.costDelta) {
							best.assignIdx = idx
							best.costDelta = delta
							best.score = scoreVal
							best.insertOk = true
						}
					}
				}
				if !ok && !isNew {
					dispatch.Assigns[idx].RemoveShip(shipID)
					dispatch.Assigns[idx].GenRoute()
				}
			}
			if isNew && ok {
				scoreVal := 0.0
				if (!best.insertOk) || (scoreVal < best.score) {
					best.assignIdx = idx
					best.costDelta = dispatch.Assigns[idx].Cost
					best.score = scoreVal
					best.insertOk = true
				}
			}
			if isNew && ok {
				dispatch.Assigns[idx].RemoveShip(shipID)
			}
		}

		if best.insertOk {
			targetIdx := best.assignIdx
			isNewTarget := targetIdx >= dispatch.AssignsLen
			dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[targetIdx].GenRoute()
			if isNewTarget {
				dispatch.AssignsLen++
				if dispatch.AssignsLen > MAXASSIGNS {
					dispatch.AssignsLen = MAXASSIGNS
				}
			}
			continue
		}

		fallbackInserted := false
		for fi := 0; fi < limitCheck; fi++ {
			idx := checkIndices[fi]
			isNewF := idx >= dispatch.AssignsLen
			ok := dispatch.Assigns[idx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost >= 0 {
					if isNewF {
						dispatch.AssignsLen++
						if dispatch.AssignsLen > MAXASSIGNS {
							dispatch.AssignsLen = MAXASSIGNS
						}
					}
					fallbackInserted = true
					break
				} else {
					dispatch.Assigns[idx].RemoveShip(shipID)
					dispatch.Assigns[idx].GenRoute()
				}
			}
		}
		if !fallbackInserted && dispatch.AssignsLen < MAXASSIGNS {
			idx := dispatch.AssignsLen
			ok := dispatch.Assigns[idx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[idx].GenRoute()
				if dispatch.Assigns[idx].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[idx].RemoveShip(shipID)
					dispatch.Assigns[idx].GenRoute()
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

