Greedy insertion with cheapest feasible assign selection using incremental route evaluation and fallback to first empty assign if all inserts fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    for shipIDOffset := range oris {
        bestAssignIdx := -1
        bestDelta := 0.0
        origCosts := make([]float64, len(dispatch.Assigns))
        for i := 0; i < dispatch.AssignsLen; i++ {
            origCosts[i] = dispatch.Assigns[i].Cost
        }
        trialAssignsLen := dispatch.AssignsLen
        if trialAssignsLen < MAXASSIGNS {
            trialAssignsLen++
        }
        for ii := 0; ii < trialAssignsLen; ii++ {
            idx := ii % MAXASSIGNS
            added := false
            oldCost := dispatch.Assigns[idx].Cost
            if dispatch.Assigns[idx].AddShip(total_ship+shipIDOffset, oris[shipIDOffset], dess[shipIDOffset]) {
                added = true
                dispatch.Assigns[idx].GenRoute()
                if dispatch.Assigns[idx].Cost >= 0 {
                    delta := dispatch.Assigns[idx].Cost - oldCost
                    if bestAssignIdx == -1 || delta < bestDelta {
                        bestDelta = delta
                        bestAssignIdx = idx
                    }
                }
            }
            if added {
                dispatch.Assigns[idx].RemoveShip(total_ship + shipIDOffset)
                dispatch.Assigns[idx].GenRoute()
            }
        }
        if bestAssignIdx != -1 {
            dispatch.Assigns[bestAssignIdx].AddShip(total_ship+shipIDOffset, oris[shipIDOffset], dess[shipIDOffset])
            dispatch.Assigns[bestAssignIdx].GenRoute()
            if bestAssignIdx >= dispatch.AssignsLen {
                dispatch.AssignsLen = bestAssignIdx + 1
            }
        } else {
            fallbackDone := false
            for ii := 0; ii < MAXASSIGNS; ii++ {
                idx := ii
                if dispatch.Assigns[idx].AddShip(total_ship+shipIDOffset, oris[shipIDOffset], dess[shipIDOffset]) {
                    dispatch.Assigns[idx].GenRoute()
                    if dispatch.Assigns[idx].Cost >= 0 {
                        if idx >= dispatch.AssignsLen {
                            dispatch.AssignsLen = idx + 1
                        }
                        fallbackDone = true
                        break
                    } else {
                        dispatch.Assigns[idx].RemoveShip(total_ship + shipIDOffset)
                        dispatch.Assigns[idx].GenRoute()
                    }
                }
            }
            if !fallbackDone {
                for ii := 0; ii < MAXASSIGNS; ii++ {
                    idx := ii
                    if dispatch.Assigns[idx].AddShip(total_ship+shipIDOffset, oris[shipIDOffset], dess[shipIDOffset]) {
                        dispatch.Assigns[idx].GenRoute()
                        if idx >= dispatch.AssignsLen {
                            dispatch.AssignsLen = idx + 1
                        }
                        break
                    }
                }
            }
        }
    }
    dispatch.RenewnTotalCost()
