func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    // Helper to compute insertion delta without permanent change
    tryInsert := func(assignIdx int, shipID int, ori, des Station) (bool, float64, Assign) {
        tmp := dispatch.Assigns[assignIdx]
        ok := tmp.AddShip(shipID, ori, des)
        if !ok {
            return false, 0, tmp
        }
        tmp.GenRoute()
        if tmp.Cost < 0 {
            tmp.RemoveShip(shipID)
            tmp.GenRoute()
            return false, 0, tmp
        }
        delta := tmp.Cost - dispatch.Assigns[assignIdx].Cost
        return true, delta, tmp
    }

    for jj := range oris {
        bestIdx := -1
        bestDelta := 1e308
        var bestAssign Assign

        // Try each existing assign, including empty ones up to current length
        for ii := 0; ii < dispatch.AssignsLen; ii++ {
            feasible, delta, cand := tryInsert(ii, total_ship+jj, oris[jj], dess[jj])
            if feasible && delta < bestDelta {
                bestDelta = delta
                bestIdx = ii
                bestAssign = cand
            }
        }

        // Also try appending to a fresh assign within MAXASSIGNS
        if dispatch.AssignsLen < MAXASSIGNS {
            ii := dispatch.AssignsLen
            feasible, delta, cand := tryInsert(ii, total_ship+jj, oris[jj], dess[jj])
            if feasible && delta < bestDelta {
                bestDelta = delta
                bestIdx = ii
                bestAssign = cand
            }
        }

        if bestIdx >= 0 {
            // Commit the best found insertion
            dispatch.Assigns[bestIdx] = bestAssign
            if bestIdx >= dispatch.AssignsLen {
                dispatch.AssignsLen++
            }
        } else {
            // Fallback safe seed: find first empty slot beyond current len if any, otherwise first empty within current len
            placed := false
            for ii := dispatch.AssignsLen; ii < MAXASSIGNS; ii++ {
                if dispatch.Assigns[ii].StationsLen == 0 {
                    ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
                    if ok {
                        dispatch.Assigns[ii].GenRoute()
                        if dispatch.Assigns[ii].Cost >= 0 {
                            dispatch.AssignsLen = ii + 1
                            placed = true
                            break
                        } else {
                            dispatch.Assigns[ii].RemoveShip(total_ship + jj)
                            dispatch.Assigns[ii].GenRoute()
                        }
                    }
                }
            }
            if !placed {
                for ii := 0; ii < dispatch.AssignsLen; ii++ {
                    if dispatch.Assigns[ii].StationsLen == 0 {
                        ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
                        if ok {
                            dispatch.Assigns[ii].GenRoute()
                            if dispatch.Assigns[ii].Cost >= 0 {
                                placed = true
                                break
                            } else {
                                dispatch.Assigns[ii].RemoveShip(total_ship + jj)
                                dispatch.Assigns[ii].GenRoute()
                            }
                        }
                    }
                }
            }
            // If still not placed, force into a new assign even if cost negative (should rarely happen)
            if !placed && dispatch.AssignsLen < MAXASSIGNS {
                ii := dispatch.AssignsLen
                dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
                dispatch.Assigns[ii].GenRoute()
                dispatch.AssignsLen++
            }
        }
    }
