	for oi := 0; oi < orders; oi++ {
		candidates := make([]candidate, 0, dispatch.AssignsLen+1)
		bestIdx := -1
		bestDelta := 1e18
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
